import React, { useState, useCallback, useMemo, useRef } from 'react';
import {
  Button,
  Input,
  MoneyInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  type LinListToolbarActionDef,
} from '@linm-soft-org/linm-web-common-components';
import { useApprovalFlowPermissions } from '../../../hooks/useApprovalFlowPermissions';
import { useAppDispatch } from '../../../store/hooks';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { ApprovalStepDto } from '../../../services/mh/models';
import { approvalFlowPageLabels as labels } from '../../../constants/approvalFlowPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { formatMoneyVnd } from '../../../utils/formatters';
import { FormMode, isEditingMode, isViewMode } from '../../../components/form/FormMode';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-mh-approval-flow';
const PAGE_ID = 'mh-approval-flow';

const emptyStep = (): ApprovalStepDto => ({
  sequence: 1,
  roleName: '',
  approverName: '',
  minAmount: 0,
});

const cloneSteps = (rows: ApprovalStepDto[]): ApprovalStepDto[] =>
  rows.map(row => ({ ...row }));

const ApprovalFlowPage: React.FC = () => {
  const { canWrite } = useApprovalFlowPermissions();
  const dispatch = useAppDispatch();
  const [steps, setSteps] = useState<ApprovalStepDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [formMode, setFormMode] = useState(FormMode.View);
  const snapshotRef = useRef<ApprovalStepDto[]>([]);

  const isEditing = isEditingMode(formMode);
  const isView = isViewMode(formMode);
  const hasRows = steps.length > 0;

  const load = useCallback(() => {
    setLoading(true);
    purchasingService.getApprovalFlow()
      .then(data => {
        const rows = data.length ? data : [];
        setSteps(rows);
        setFormMode(FormMode.View);
      })
      .catch(err => dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.loadError),
        type: 'error',
      }))
      .finally(() => setLoading(false));
  }, [dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const updateStep = (idx: number, patch: Partial<ApprovalStepDto>) => {
    setSteps(prev => prev.map((s, i) => (i === idx ? { ...s, ...patch } : s)));
  };

  const handleEdit = useCallback(() => {
    snapshotRef.current = cloneSteps(steps.length ? steps : [emptyStep()]);
    if (!steps.length) setSteps([emptyStep()]);
    setFormMode(FormMode.Edit);
  }, [steps]);

  const handleCreate = useCallback(() => {
    snapshotRef.current = [];
    setSteps([emptyStep()]);
    setFormMode(FormMode.Create);
  }, []);

  const handleCancel = useCallback(() => {
    const snap = snapshotRef.current;
    setSteps(snap.length ? cloneSteps(snap) : []);
    setFormMode(FormMode.View);
  }, []);

  const handleAddStep = useCallback(() => {
    setSteps(prev => [...prev, { ...emptyStep(), sequence: prev.length + 1 }]);
  }, []);

  const handleSave = useCallback(async () => {
    setSaving(true);
    try {
      const payload = steps.map((s, i) => ({ ...s, sequence: i + 1 }));
      const saved = await purchasingService.saveApprovalFlow(payload);
      setSteps(saved.length ? saved : payload);
      dispatchAppToast(dispatch, { message: labels.saveSuccess, type: 'success' });
      setFormMode(FormMode.View);
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  }, [steps, dispatch, load]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const headerHint = useMemo(() => {
    if (formMode === FormMode.Create) return labels.createHint;
    if (formMode === FormMode.Edit) return labels.editHint;
    return labels.viewHint;
  }, [formMode]);

  const minThreshold = useMemo(
    () => (steps.length ? Math.min(...steps.map(s => s.minAmount)) : 0),
    [steps],
  );

  const toolbarActions = useMemo((): LinListToolbarActionDef[] => {
    const left: LinListToolbarActionDef[] = [
      {
        id: 'refresh',
        placement: 'left',
        action: 'refresh',
        visible: true,
        disabled: isEditing,
        onClick: load,
        testId: `${TEST_ID}-toolbar-refresh-btn`,
      },
    ];

    if (isView) {
      const right: LinListToolbarActionDef[] = canWrite
        ? (hasRows
          ? [{
            id: 'edit',
            placement: 'right',
            action: 'edit',
            visible: true,
            onClick: handleEdit,
            testId: `${TEST_ID}-toolbar-edit-btn`,
          }]
          : [{
            id: 'create',
            placement: 'right',
            action: 'create',
            variant: 'primary',
            visible: true,
            onClick: handleCreate,
            testId: `${TEST_ID}-toolbar-add-btn`,
          }])
        : [];
      return [...left, ...right];
    }

    const editRight: LinListToolbarActionDef[] = [
      {
        id: 'add-step',
        placement: 'right',
        label: labels.addStep,
        variant: 'secondary',
        visible: true,
        disabled: saving,
        onClick: handleAddStep,
        testId: `${TEST_ID}-toolbar-add-step-btn`,
      },
      {
        id: 'cancel',
        placement: 'right',
        label: labels.cancel,
        variant: 'secondary',
        visible: true,
        disabled: saving,
        onClick: handleCancel,
        testId: `${TEST_ID}-toolbar-cancel-btn`,
      },
      {
        id: 'save',
        placement: 'right',
        visible: true,
        testId: `${TEST_ID}-toolbar-save-btn`,
        render: () => (
          <Button
            variant="primary"
            size="sm"
            loading={saving}
            disabled={saving}
            data-testid={`${TEST_ID}-save`}
            onClick={handleSave}
          >
            {labels.save}
          </Button>
        ),
      },
    ];
    return [...left, ...editRight];
  }, [
    isView,
    isEditing,
    hasRows,
    canWrite,
    load,
    handleEdit,
    handleCreate,
    handleCancel,
    handleAddStep,
    handleSave,
    saving,
  ]);

  const listBody = !showTableLoading && !hasRows ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>
  ) : !showTableLoading ? (
    <>
      <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table`}>
        <table className={erp.table}>
          <thead>
            <tr>
              <th>{labels.colSequence}</th>
              <th>{labels.colRole}</th>
              <th>{labels.colApprover}</th>
              <th className={erp.colRight}>{labels.colMinAmount}</th>
              {isEditing && <th className={erp.colActions} aria-label="Thao tác" />}
            </tr>
          </thead>
          <tbody>
            {steps.map((step, idx) => (
              <tr key={idx} data-testid={`${TEST_ID}-row-${idx + 1}`}>
                <td>{idx + 1}</td>
                <td>
                  {isView ? (
                    <span data-testid={`${TEST_ID}-row-${idx + 1}-role`}>{step.roleName || '—'}</span>
                  ) : (
                    <Input
                      value={step.roleName}
                      onChange={e => updateStep(idx, { roleName: e.target.value })}
                      size="small"
                      data-testid={`${TEST_ID}-row-${idx + 1}-role`}
                    />
                  )}
                </td>
                <td>
                  {isView ? (
                    <span data-testid={`${TEST_ID}-row-${idx + 1}-approver`}>{step.approverName || '—'}</span>
                  ) : (
                    <Input
                      value={step.approverName}
                      onChange={e => updateStep(idx, { approverName: e.target.value })}
                      size="small"
                      data-testid={`${TEST_ID}-row-${idx + 1}-approver`}
                    />
                  )}
                </td>
                <td className={erp.colRight}>
                  {isView ? (
                    <span data-testid={`${TEST_ID}-row-${idx + 1}-min`}>
                      {formatMoneyVnd(step.minAmount)}
                    </span>
                  ) : (
                    <MoneyInput
                      value={step.minAmount}
                      onChange={val => updateStep(idx, { minAmount: val })}
                      data-testid={`${TEST_ID}-row-${idx + 1}-min`}
                    />
                  )}
                </td>
                {isEditing && (
                  <td className={erp.colActions}>
                    <button
                      type="button"
                      className={erp.actionBtn}
                      onClick={() => setSteps(p => p.filter((_, i) => i !== idx))}
                      disabled={steps.length <= 1}
                      title="Xóa"
                      data-testid={`${TEST_ID}-row-${idx + 1}-delete`}
                    >
                      <i className="fas fa-trash" />
                    </button>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div className={erp.footer} data-testid={`${TEST_ID}-footer`}>
        <span className={erp.totalCount}>
          {labels.footerSummary(steps.length, minThreshold)}
        </span>
      </div>
    </>
  ) : null;

  return (
    <div
      className={erp.catalogListRoot}
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
      data-form-mode={formMode}
    >
      <LinPageLayout
        kind="catalog"
        filterBarLayout="compact"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-project-diagram',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        toolbarProps={{
          testIdPrefix: TEST_ID,
          profile: 'catalog',
          actions: toolbarActions,
        }}
        listTitle={labels.listTitle}
        showTableLoading={showTableLoading}
        skeletonRows={4}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default ApprovalFlowPage;
